package com.voiddeveloper.tictactoe.data.protodatastoremanagerimport android.content.Contextimport androidx.datastore.core.DataStoreimport androidx.datastore.dataStoreimport com.voiddeveloper.tictactoe.data.datastore.proto.GameDetailsCacheimport com.voiddeveloper.tictactoe.domain.serializers.GameDetailCacheSerializerimport kotlinx.coroutines.flow.firstOrNullclass GameDetailsProtoDataStoreManager (val context: Context) {    private val Context.autoSaveDataStore: DataStore<GameDetailsCache> by dataStore(        fileName = "game_details_cache.pb",        serializer = GameDetailCacheSerializer    )    suspend fun readAutoSaveUserPref(): GameDetailsCache {        return context.autoSaveDataStore.data.firstOrNull()            ?: GameDetailsCache.getDefaultInstance()    }    suspend fun updateAutoSaveUserPref(        update: (GameDetailsCache.Builder) -> Unit    ) {        context.autoSaveDataStore.updateData { current ->            current.toBuilder()                .apply(update)                .build()        }    }}